const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// --- Credential Management ---
// Environment variables are the recommended way to manage credentials in Cloud Functions.
// These variables must be set in your Cloud Function environment during deployment.
// For example, using `gcloud functions deploy --set-env-vars KEY=VALUE` or via the Cloud Console.

const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const SENDER_EMAIL = process.env.SENDER_EMAIL; // Verified sender email in SendGrid

const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER; // Your Twilio phone number (e.g., +15017122661)

// --- Initialize SendGrid ---
if (SENDGRID_API_KEY) {
  sgMail.setApiKey(SENDGRID_API_KEY);
  console.log('SendGrid API key loaded.');
} else {
  console.warn('SENDGRID_API_KEY environment variable is not set. Email sending will be disabled.');
}

// --- Initialize Twilio ---
let twilioClient;
if (TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN) {
  twilioClient = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);
  console.log('Twilio client initialized.');
} else {
  console.warn('TWILIO_ACCOUNT_SID or TWILIO_AUTH_TOKEN environment variables are not set. SMS sending will be disabled.');
}

/**
 * Sends an email using SendGrid.
 * @param {string} to - Recipient email address.
 * @param {string} subject - Email subject.
 * @param {string} text - Plain text content.
 * @param {string} [html] - HTML content (optional, falls back to text if not provided).
 * @returns {Promise<object>} - A promise that resolves with success status.
 * @throws {Error} If SendGrid is not configured or email sending fails.
 */
async function sendEmail(to, subject, text, html) {
  if (!SENDGRID_API_KEY || !SENDER_EMAIL) {
    throw new Error('SendGrid is not properly configured. Check SENDGRID_API_KEY and SENDER_EMAIL environment variables.');
  }

  const msg = {
    to: to,
    from: SENDER_EMAIL,
    subject: subject,
    text: text,
    html: html || text, // Use HTML if provided, otherwise fallback to plain text
  };

  try {
    await sgMail.send(msg);
    console.log(`Email sent successfully to ${to}`);
    return { success: true, message: 'Email sent successfully.' };
  } catch (error) {
    console.error('Error sending email:', error);
    // Log SendGrid specific error details if available
    if (error.response && error.response.body && error.response.body.errors) {
      console.error('SendGrid error details:', error.response.body.errors);
      throw new Error(`Failed to send email: ${error.response.body.errors.map(e => e.message).join(', ')}`);
    }
    throw new Error(`Failed to send email: ${error.message}`);
  }
}

/**
 * Sends an SMS using Twilio.
 * @param {string} to - Recipient phone number (e.g., +1234567890).
 * @param {string} body - SMS message body.
 * @returns {Promise<object>} - A promise that resolves with success status and Twilio SID.
 * @throws {Error} If Twilio is not configured or SMS sending fails.
 */
async function sendSms(to, body) {
  if (!twilioClient || !TWILIO_PHONE_NUMBER) {
    throw new Error('Twilio is not properly configured. Check TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, and TWILIO_PHONE_NUMBER environment variables.');
  }

  try {
    const message = await twilioClient.messages.create({
      body: body,
      to: to,
      from: TWILIO_PHONE_NUMBER,
    });
    console.log(`SMS sent successfully to ${to}. SID: ${message.sid}`);
    return { success: true, message: 'SMS sent successfully.', sid: message.sid };
  } catch (error) {
    console.error('Error sending SMS:', error);
    throw new Error(`Failed to send SMS: ${error.message}`);
  }
}

/**
 * Main Cloud Function entry point.
 * Handles incoming HTTP POST requests to send emails or SMS.
 *
 * Request Body Structure:
 * For Email:
 * {
 *   "type": "email",
 *   "payload": {
 *     "to": "recipient@example.com",
 *     "subject": "Hello from Cloud Function",
 *     "text": "This is a test email sent from a Node.js Cloud Function.",
 *     "html": "<strong>This is a test email sent from a Node.js Cloud Function.</strong>"
 *   }
 * }
 *
 * For SMS:
 * {
 *   "type": "sms",
 *   "payload": {
 *     "to": "+1234567890",
 *     "body": "This is a test SMS from a Node.js Cloud Function."
 *   }
 * }
 *
 * @param {object} req - Express.js request object.
 * @param {object} res - Express.js response object.
 */
module.exports = async (req, res) => {
  // Set CORS headers for preflight requests
  if (req.method === 'OPTIONS') {
    res.set('Access-Control-Allow-Origin', '*');
    res.set('Access-Control-Allow-Methods', 'POST');
    res.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
    res.set('Access-Control-Max-Age', '3600');
    return res.status(204).send('');
  }

  // Set CORS headers for actual requests
  res.set('Access-Control-Allow-Origin', '*');
  res.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');

  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed. Only POST requests are accepted.' });
  }

  const { type, payload } = req.body;

  if (!type || !payload) {
    return res.status(400).json({ error: 'Missing "type" or "payload" in request body.' });
  }

  try {
    let result;
    switch (type) {
      case 'email':
        const { to: emailTo, subject, text, html } = payload;
        if (!emailTo || !subject || !text) {
          return res.status(400).json({ error: 'Missing required fields for email: to, subject, text.' });
        }
        result = await sendEmail(emailTo, subject, text, html);
        break;

      case 'sms':
        const { to: smsTo, body: smsBody } = payload;
        if (!smsTo || !smsBody) {
          return res.status(400).json({ error: 'Missing required fields for SMS: to, body.' });
        }
        result = await sendSms(smsTo, smsBody);
        break;

      default:
        return res.status(400).json({ error: `Unknown message type: "${type}". Must be 'email' or 'sms'.` });
    }
    res.status(200).json(result);
  } catch (error) {
    console.error('Function execution error:', error.message);
    res.status(500).json({ error: error.message });
  }
};

